// RegisterAmelisoServiceHandlerWithProvider registers handlers for the specified LLM provider
func RegisterAmelisoServiceHandlerWithProvider(s runtime.MCPServer, srv AmelisoServiceServer, provider runtime.LLMProvider, opts ...runtime.Option) {
	switch provider {
	case runtime.LLMProviderOpenAI:
		RegisterAmelisoServiceHandlerOpenAI(s, srv, opts...)
	case runtime.LLMProviderStandard:
		fallthrough
	default:
		RegisterAmelisoServiceHandler(s, srv, opts...)
	}
}

